function App() {
  return (
    <div className="flex min-h-screen items-center justify-center bg-slate-900">
      <div className="rounded-xl bg-white p-8 shadow-2xl">
        <h1 className="text-3xl font-bold text-blue-600">
          Hudson Manpower Project
        </h1>
        <p className="mt-2 text-gray-600">
          Tailwind v4 + React.js is working perfectly on MacBook M4!
        </p>
        <button className="mt-4 rounded-lg bg-blue-600 px-6 py-2 text-white hover:bg-blue-700 transition-colors">
          Explore Jobs
        </button>
      </div>
    </div>
  );
}

export default App;
